import { Component, Event, EventEmitter, h, Host, Prop } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';

/**
 * Secondary navigation header used for page titles, back button, breadcrumbs, and actions.
 *
 * Layout:
 * - Title row (back button + title + actions)
 * - Breadcrumb row beneath the title
 *
 * Variants:
 * - 'default': Divider is controlled by showDivider, background is bg-page-default.
 * - 'page-with-left-panel': Divider is controlled by showDivider, background is bg-page-default-alt.
 *
 * @slot breadcrumbs - Breadcrumb row inside the header, below the title row.
 * @slot actions - Trailing actions on the right of the title row (e.g. X or primary button).
 * @slot back-icon - Optional override for the back icon button.
 */
@Component({
  tag: 'wdpr-secondary-navigation',
  shadow: true,
})
export class WdprSecondaryNavigation {
  /**
   * Page title shown in the secondary navigation.
   * Also used as the accessible label for the section.
   */
  @Prop() pageTitle!: string;

  /**
   * Variant of the secondary navigation.
   * - 'default': Divider is controlled by showDivider, background is bg-page-default.
   * - 'page-with-left-panel': Divider is controlled by showDivider, background is bg-page-default-alt.
   */
  @Prop() variant: 'default' | 'page-with-left-panel' = 'default';

  /**
   * Whether the back icon button should be rendered.
   */
  @Prop() showBackButton = false;

  /**
   * Controls the horizontal divider beneath the header.
   */
  @Prop() showDivider = true;

  /**
   * Whether the close icon button should be rendered.
   */
  @Prop() showCloseButton = true;

  /**
   * Visually hides the page title but keeps it accessible to assistive technologies.
   */
  @Prop() hideTitle = false;

  /**
   * Accessible label for the back button.
   */
  @Prop() backButtonLabel = 'Go back';

  /**
   * The HTML tag to use for the page title. Defaults to 'h1'.
   */
  @Prop() titleTag: 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6' = 'h1';

  /**
   * Event emitted when the back button is clicked.
   */
  @Event({ eventName: 'backButtonClicked' }) backButtonClicked!: EventEmitter<void>;

  private _onBackButtonClick = (): void => {
    this.backButtonClicked.emit();
  };

  /**
   * Event emitted when the close button is clicked.
   */
  @Event({ eventName: 'wdprCloseClick' }) wdprCloseClick!: EventEmitter<void>;

  private _onCloseButtonClick = (): void => {
    this.wdprCloseClick.emit();
  };

  private get _rootClasses(): string {
    const bgClass = this.variant === 'default' ? 'bg-page-default' : 'bg-page-default-alt';

    return customTwMerge('flex flex-col w-full', bgClass, 'rounded-tl-300 rounded-tr-300');
  }

  private get _headerClasses(): string {
    return customTwMerge('flex flex-col w-full', 'rounded-300', 'py-200 px-300', 'min-h-[64px]', 'gap-050');
  }

  private get _titleRowClasses(): string {
    return customTwMerge('flex items-center justify-between w-full');
  }

  private get _titleGroupClasses(): string {
    return customTwMerge('flex items-center min-w-0 gap-150 flex-1');
  }

  private get _titleTextClasses(): string {
    return customTwMerge(
      'truncate text-text-heading text-[length:var(--font-size-20)] font-body-default leading-[length:var(--line-height-24)] tracking--05',
      this.hideTitle ? 'sr-only' : '',
    );
  }

  private get _actionsClasses(): string {
    return customTwMerge('flex items-center gap-150 shrink-0');
  }

  private get _breadcrumbContainerClasses(): string {
    return customTwMerge('pl-[41px] w-full');
  }

  render() {
    const TitleTag = this.titleTag; // Dynamically set the tag

    return (
      <Host>
        <section class={this._rootClasses} aria-label={this.pageTitle}>
          <div class={this._headerClasses}>
            <div class={this._titleRowClasses}>
              <div class={this._titleGroupClasses}>
                {this.showBackButton && (
                  <slot name="back-icon">
                    <wdpr-icon-button variant="primary" size="medium" iconName="previous-caret-2.0" a11yLabel={this.backButtonLabel} onClicked={this._onBackButtonClick} />
                  </slot>
                )}

                {this.showBackButton && <div class="hidden md:flex h-400 items-stretch">{!this.hideTitle && <wdpr-divider orientation="vertical" aria-hidden="true" />}</div>}

                <TitleTag class={this._titleTextClasses}>{this.pageTitle}</TitleTag>
              </div>

              <div class={this._actionsClasses}>
                <slot name="actions">
                  {this.showCloseButton && <wdpr-icon-button variant="bgPrimary" size="small" iconName="close-reversed" a11yLabel="Close" onClick={this._onCloseButtonClick} />}
                </slot>
              </div>
            </div>

            <div class={this._breadcrumbContainerClasses}>
              <slot name="breadcrumbs" />
            </div>
          </div>

          {this.showDivider && <wdpr-divider orientation="horizontal" aria-hidden="true" />}
        </section>
      </Host>
    );
  }
}
